INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_circulacao_conduta' LIMIT 1), 'Agente da STTP flagra condutor que, em via arterial de Campina Grande, utiliza telefone celular encostado ao ouvido enquanto conduz motocicleta em movimento. O condutor argumenta que a infração seria apenas leve por não colocar outros usuários em risco imediato. À luz do CTB, assinale a alternativa CORRETA:', 'A conduta configura infração leve, pois não há menção expressa a apreensão do veículo.', 'A utilização de telefone celular sem dispositivo mãos-livres configura infração média.', 'Somente é infração se o condutor estiver em velocidade superior ao limite da via.', 'A autuação é inválida, pois motociclistas estão dispensados do uso de cinto e de restrições a celular.', NULL, 'B', 'caso_pratico', 'pegadinha_pode_deve', 3, '{"o_que_testa":"Infração por dirigir utilizando telefone celular (art. 252, VI) e sua classificação.","fundamento_legal":"CTB, art. 252, VI: dirigir o veículo utilizando-se de fones nos ouvidos conectados a aparelhagem sonora ou de telefone celular — infração média; penalidade multa.","passo_a_passo":["Condutor usa celular ao ouvido em motocicleta em movimento.","A) Erra: a infração é média, não leve.","B) Correta: art. 252, VI — celular sem mãos-livres = infração média.","C) Erra: não condiciona a infração ao excesso de velocidade.","D) Erra: motociclistas não estão dispensados; o inciso VI não exclui motos."],"pegadinha":"Candidato subestima a gravidade (leve) ou acha que moto está fora do alcance do art. 252.","macete":"Celular na orelha ao volante = média (art. 252, VI).","estudo_reverso":["CTB art. 252","CTB art. 65","CTB art. 167"]}'::jsonb, '{"celular","art_252","conduta"}'::text[]);